// before (conceptual)
if (action === 'pr:ap') {
  await proposals.approveProposal(id);
  await telegram.send('✅ Proposal approved. Ready for execution.');
}

// after (conceptual)
if (action === 'pr:ap') {
  const result = await apiClient.post(`/api/proposals/${id}/approve`);
  if (result.executionStarted) {
    await telegram.send('✅ Proposal approved and execution started.');
  } else if (result.approved) {
    await telegram.send('✅ Proposal approved. No executor configured.');
  } else {
    await telegram.send('⚠️ Proposal approved, but execution could not be started.');
  }
}
